SELECT AVG(farmgate_price) AS average_farmgate_price
FROM farmgate_prices
WHERE crop_id = 1;

SELECT AVG(farmgate_price) AS average_price
FROM farmgate_prices
WHERE crop_id = 0;

SELECT crop_name, yield_per_hectare
FROM crops
ORDER BY yield_per_hectare DESC;

SELECT MAX(farmgate_price) AS max_price
FROM farmgate_prices
WHERE crop_id = 0;

SELECT DISTINCT d.district_name
FROM production_data p
INNER JOIN districts d ON p.district_id = d.district_id;
